UPDATE api_access SET

    status = #{status},
    rate_limit = #{rate_limit}
WHERE id_user = ${employee_id}

mapper.select:
WITH RECURSIVE days AS ( SELECT 1 AS `day` UNION ALL SELECT `day` + 1 FROM days WHERE `day` < DAY(LAST_DAY(NOW())) ), data AS ( SELECT DAY(time) AS `day`, COUNT(*) AS total FROM api_usage WHERE id_user = #{employee_id} AND time >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)
AND id_endpoint = #{id_enpoint}
GROUP BY DAY(time) ) SELECT DATE_FORMAT(CONCAT(YEAR(NOW()), '-', MONTH(NOW()), '-', d.`day`), '%m-%d-%Y') AS label, IFNULL(t.total, 0) AS value FROM days d LEFT JOIN data t ON t.`day` = d.`day` ORDER BY d.`day`;

WITH RECURSIVE months AS ( SELECT 1 AS `month` UNION ALL SELECT `month` + 1 FROM months WHERE `month` < 12 ), data AS ( SELECT MONTH(time) AS `month`, COUNT(*) AS total FROM api_usage WHERE id_user = #{employee_id} AND time >= DATE_FORMAT(CURDATE(), '%Y-01-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-01-01'), INTERVAL 1 YEAR)
AND id_endpoint = #{id_enpoint}
GROUP BY MONTH(time) ) SELECT DATE_FORMAT(CONCAT(YEAR(NOW()), '-', m.`month`, '-01'), '%b-%Y') AS label, IFNULL(d.total, 0) AS value FROM months m LEFT JOIN data d ON d.`month` = m.`month` ORDER BY m.`month`;

WITH quarters AS ( SELECT 1 AS q UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 ), data AS ( SELECT QUARTER(time) AS q, COUNT(*) AS total FROM api_usage WHERE id_user = #{employee_id} AND time >= DATE_FORMAT(CURDATE(), '%Y-01-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-01-01'), INTERVAL 1 YEAR)
AND id_endpoint = #{id_enpoint}
GROUP BY QUARTER(time) ) SELECT CONCAT('Q', q.q, '-', YEAR(NOW())) AS label, IFNULL(d.total, 0) AS value FROM quarters q LEFT JOIN data d ON d.q = q.q ORDER BY q.q;

WITH RECURSIVE years AS (
    SELECT COALESCE(MIN(YEAR(time)), YEAR(NOW())) AS y FROM api_usage WHERE id_user = #{employee_id}
    UNION ALL
    SELECT y + 1 FROM years WHERE y < YEAR(NOW())
),
data AS (
    SELECT
        YEAR(time) AS y,
        COUNT(*) AS total
    FROM api_usage
    WHERE id_user = #{employee_id}

            AND id_endpoint = #{id_enpoint}

    GROUP BY YEAR(time)
)
SELECT
    CONCAT(years.y, '') AS label,
    IFNULL(d.total, 0) AS value
FROM years
LEFT JOIN data d ON d.y = years.y
ORDER BY years.y;

